// App.js
import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
  ScrollView,
} from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as SecureStore from 'expo-secure-store';
import * as Crypto from 'expo-crypto';

// OAuth Configuration
// SECURITY: client_id is acceptable in mobile apps (public clients).
// client_secret should NOT be embedded in mobile apps - use PKCE instead.
// If your server requires a client_secret, it should be handled server-side
// via a backend proxy (Backend-for-Frontend pattern).
const OAUTH_CONFIG = {
  clientId: process.env.EXPO_PUBLIC_OAUTH_CLIENT_ID || 'your-client-id',
  // DO NOT embed client_secret in mobile apps. Mobile apps are public clients.
  // Use PKCE (Proof Key for Code Exchange) instead.
  authorizationEndpoint:
    process.env.EXPO_PUBLIC_AUTH_ENDPOINT || 'https://auth.example.com/authorize',
  tokenEndpoint:
    process.env.EXPO_PUBLIC_TOKEN_ENDPOINT || 'https://auth.example.com/token',
  revocationEndpoint:
    process.env.EXPO_PUBLIC_REVOKE_ENDPOINT || 'https://auth.example.com/revoke',
  userInfoEndpoint:
    process.env.EXPO_PUBLIC_USERINFO_ENDPOINT || 'https://auth.example.com/userinfo',
  scopes: ['openid', 'profile', 'email', 'offline_access'],
  redirectUri: AuthSession.makeRedirectUri({
    scheme: 'myapp',
    path: 'callback',
  }),
};

const SECURE_STORE_KEYS = {
  ACCESS_TOKEN: 'oauth_access_token',
  REFRESH_TOKEN: 'oauth_refresh_token',
  TOKEN_EXPIRY: 'oauth_token_expiry',
  ID_TOKEN: 'oauth_id_token',
};

// Token refresh buffer - refresh 5 minutes before expiry
const TOKEN_REFRESH_BUFFER_SECONDS = 300;

// PKCE Helper Functions
async function generateCodeVerifier() {
  const randomBytes = await Crypto.getRandomBytesAsync(32);
  return base64URLEncode(randomBytes);
}

async function generateCodeChallenge(verifier) {
  const digest = await Crypto.digestStringAsync(
    Crypto.CryptoDigestAlgorithm.SHA256,
    verifier,
    { encoding: Crypto.CryptoEncoding.BASE64 }
  );
  return base64URLEncodeString(digest);
}

function base64URLEncode(buffer) {
  const base64 = btoa(String.fromCharCode(...new Uint8Array(buffer)));
  return base64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

function base64URLEncodeString(str) {
  return str.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

async function generateState() {
  const randomBytes = await Crypto.getRandomBytesAsync(16);
  return base64URLEncode(randomBytes);
}

// Secure Token Storage
class TokenStorage {
  static async saveTokens({ accessToken, refreshToken, expiresIn, idToken }) {
    try {
      const expiryTime = Date.now() + expiresIn * 1000;

      await SecureStore.setItemAsync(SECURE_STORE_KEYS.ACCESS_TOKEN, accessToken);
      await SecureStore.setItemAsync(SECURE_STORE_KEYS.TOKEN_EXPIRY, expiryTime.toString());

      if (refreshToken) {
        await SecureStore.setItemAsync(SECURE_STORE_KEYS.REFRESH_TOKEN, refreshToken);
      }

      if (idToken) {
        await SecureStore.setItemAsync(SECURE_STORE_KEYS.ID_TOKEN, idToken);
      }
    } catch (error) {
      console.error('Failed to save tokens securely:', error);
      throw new Error('Token storage failed');
    }
  }

  static async getAccessToken() {
    try {
      return await SecureStore.getItemAsync(SECURE_STORE_KEYS.ACCESS_TOKEN);
    } catch {
      return null;
    }
  }

  static async getRefreshToken() {
    try {
      return await SecureStore.getItemAsync(SECURE_STORE_KEYS.REFRESH_TOKEN);
    } catch {
      return null;
    }
  }

  static async getTokenExpiry() {
    try {
      const expiry = await SecureStore.getItemAsync(SECURE_STORE_KEYS.TOKEN_EXPIRY);
      return expiry ? parseInt(expiry, 10) : null;
    } catch {
      return null;
    }
  }

  static async isTokenExpired() {
    const expiry = await this.getTokenExpiry();
    if (!expiry) return true;
    return Date.now() >= expiry - TOKEN_REFRESH_BUFFER_SECONDS * 1000;
  }

  static async clearTokens() {
    try {
      await SecureStore.deleteItemAsync(SECURE_STORE_KEYS.ACCESS_TOKEN);
      await SecureStore.deleteItemAsync(SECURE_STORE_KEYS.REFRESH_TOKEN);
      await SecureStore.deleteItemAsync(SECURE_STORE_KEYS.TOKEN_EXPIRY);
      await SecureStore.deleteItemAsync(SECURE_STORE_KEYS.ID_TOKEN);
    } catch (error) {
      console.error('Failed to clear tokens:', error);
    }
  }
}

// OAuth Service with PKCE
class OAuthService {
  static codeVerifier = null;
  static refreshPromise = null;

  static async initiateAuthorizationCodeFlow() {
    // Generate PKCE parameters
    this.codeVerifier = await generateCodeVerifier();
    const codeChallenge = await generateCodeChallenge(this.codeVerifier);
    const state = await generateState();

    // Store state for validation
    await SecureStore.setItemAsync('oauth_state', state);

    const params = new URLSearchParams({
      response_type: 'code',
      client_id: OAUTH_CONFIG.clientId,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      scope: OAUTH_CONFIG.scopes.join(' '),
      state: state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256',
    });

    const authUrl = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
    return { authUrl, state };
  }

  static async exchangeCodeForTokens(code, returnedState) {
    // Validate state parameter to prevent CSRF
    const savedState = await SecureStore.getItemAsync('oauth_state');
    if (!savedState || savedState !== returnedState) {
      throw new Error('State mismatch - possible CSRF attack');
    }

    // Clean up state
    await SecureStore.deleteItemAsync('oauth_state');

    if (!this.codeVerifier) {
      throw new Error('Code verifier not found - authorization flow was not properly initiated');
    }

    const body = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      client_id: OAUTH_CONFIG.clientId,
      code_verifier: this.codeVerifier,
      // No client_secret - using PKCE for public client
    });

    // Clear code verifier after use
    this.codeVerifier = null;

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(
        `Token exchange failed: ${errorData.error_description || errorData.error || response.statusText}`
      );
    }

    const tokenData = await response.json();

    await TokenStorage.saveTokens({
      accessToken: tokenData.access_token,
      refreshToken: tokenData.refresh_token,
      expiresIn: tokenData.expires_in || 3600,
      idToken: tokenData.id_token,
    });

    return tokenData;
  }

  static async refreshAccessToken() {
    // Deduplicate concurrent refresh requests
    if (this.refreshPromise) {
      return this.refreshPromise;
    }

    this.refreshPromise = this._performRefresh();

    try {
      const result = await this.refreshPromise;
      return result;
    } finally {
      this.refreshPromise = null;
    }
  }

  static async _performRefresh() {
    const refreshToken = await TokenStorage.getRefreshToken();

    if (!refreshToken) {
      throw new Error('No refresh token available');
    }

    const body = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAUTH_CONFIG.clientId,
      // No client_secret - public client using PKCE
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: body.toString(),
    });

    if (!response.ok) {
      // If refresh fails, clear tokens and require re-authentication
      await TokenStorage.clearTokens();
      throw new Error('Token refresh failed - re-authentication required');
    }

    const tokenData = await response.json();

    await TokenStorage.saveTokens({
      accessToken: tokenData.access_token,
      refreshToken: tokenData.refresh_token || refreshToken, // Use new refresh token if provided (rotation)
      expiresIn: tokenData.expires_in || 3600,
      idToken: tokenData.id_token,
    });

    return tokenData;
  }

  static async getValidAccessToken() {
    const isExpired = await TokenStorage.isTokenExpired();

    if (isExpired) {
      try {
        await this.refreshAccessToken();
      } catch (error) {
        throw new Error('Unable to obtain valid access token');
      }
    }

    return await TokenStorage.getAccessToken();
  }

  static async revokeTokens() {
    const accessToken = await TokenStorage.getAccessToken();
    const refreshToken = await TokenStorage.getRefreshToken();

    const revokePromises = [];

    if (refreshToken && OAUTH_CONFIG.revocationEndpoint) {
      revokePromises.push(
        fetch(OAUTH_CONFIG.revocationEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: new URLSearchParams({
            token: refreshToken,
            token_type_hint: 'refresh_token',
            client_id: OAUTH_CONFIG.clientId,
          }).toString(),
        }).catch(() => {})
      );
    }

    if (accessToken && OAUTH_CONFIG.revocationEndpoint) {
      revokePromises.push(
        fetch(OAUTH_CONFIG.revocationEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: new URLSearchParams({
            token: accessToken,
            token_type_hint: 'access_token',
            client_id: OAUTH_CONFIG.clientId,
          }).toString(),
        }).catch(() => {})
      );
    }

    await Promise.allSettled(revokePromises);
    await TokenStorage.clearTokens();
  }

  static async fetchUserInfo() {
    const accessToken = await this.getValidAccessToken();

    if (!accessToken) {
      throw new Error('No access token available');
    }

    const response = await fetch(OAUTH_CONFIG.userInfoEndpoint, {
      headers: {
        Authorization: `Bearer ${accessToken}`,
      },
    });

    if (response.status === 401) {
      // Token might have been revoked server-side, try refresh
      try {
        await this.refreshAccessToken();
        const newToken = await TokenStorage.getAccessToken();
        const retryResponse = await fetch(OAUTH_CONFIG.userInfoEndpoint, {
          headers: {
            Authorization: `Bearer ${newToken}`,
          },
        });
        if (!retryResponse.ok) {
          throw new Error('Failed to fetch user info after token refresh');
        }
        return await retryResponse.json();
      } catch {
        throw new Error('Authentication expired - please log in again');
      }
    }

    if (!response.ok) {
      throw new Error('Failed to fetch user info');
    }

    return await response.json();
  }
}

// Authenticated API client with automatic token refresh
class ApiClient {
  static async fetch(url, options = {}) {
    const accessToken = await OAuthService.getValidAccessToken();

    if (!accessToken) {
      throw new Error('Not authenticated');
    }

    const headers = {
      ...options.headers,
      Authorization: `Bearer ${accessToken}`,
    };

    let response = await fetch(url, { ...options, headers });

    // If 401, attempt token refresh and retry once
    if (response.status === 401) {
      try {
        await OAuthService.refreshAccessToken();
        const newToken = await TokenStorage.getAccessToken();
        headers.Authorization = `Bearer ${newToken}`;
        response = await fetch(url, { ...options, headers });
      } catch {
        throw new Error('Authentication expired');
      }
    }

    return response;
  }
}

// Main App Component
export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [userInfo, setUserInfo] = useState(null);
  const [error, setError] = useState(null);
  const refreshTimerRef = useRef(null);

  // Check existing authentication on app start
  useEffect(() => {
    checkExistingAuth();
    return () => {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
    };
  }, []);

  const scheduleTokenRefresh = useCallback(async () => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }

    const expiry = await TokenStorage.getTokenExpiry();
    if (!expiry) return;

    const now = Date.now();
    const refreshTime = expiry - TOKEN_REFRESH_BUFFER_SECONDS * 1000 - now;

    if (refreshTime > 0) {
      refreshTimerRef.current = setTimeout(async () => {
        try {
          await OAuthService.refreshAccessToken();
          scheduleTokenRefresh();
        } catch {
          setIsAuthenticated(false);
          setUserInfo(null);
          Alert.alert('Session Expired', 'Please log in again.');
        }
      }, refreshTime);
    } else {
      // Token is already near expiry, refresh now
      try {
        await OAuthService.refreshAccessToken();
        scheduleTokenRefresh();
      } catch {
        setIsAuthenticated(false);
        setUserInfo(null);
      }
    }
  }, []);

  const checkExistingAuth = async () => {
    try {
      const accessToken = await TokenStorage.getAccessToken();
      if (accessToken) {
        const isExpired = await TokenStorage.isTokenExpired();
        if (isExpired) {
          try {
            await OAuthService.refreshAccessToken();
          } catch {
            await TokenStorage.clearTokens();
            setIsLoading(false);
            return;
          }
        }
        setIsAuthenticated(true);
        await scheduleTokenRefresh();
        await loadUserInfo();
      }
    } catch {
      await TokenStorage.clearTokens();
    } finally {
      setIsLoading(false);
    }
  };

  const loadUserInfo = async () => {
    try {
      const info = await OAuthService.fetchUserInfo();
      setUserInfo(info);
    } catch (err) {
      console.error('Failed to load user info:', err);
    }
  };

  const handleLogin = async () => {
    setIsLoading(true);
    setError(null);

    try {
      const { authUrl, state } = await OAuthService.initiateAuthorizationCodeFlow();

      const result = await AuthSession.startAsync({
        authUrl,
        returnUrl: OAUTH_CONFIG.redirectUri,
      });

      if (result.type === 'success') {
        const { code, state: returnedState } = result.params;

        if (!code) {
          throw new Error('No authorization code received');
        }

        await OAuthService.exchangeCodeForTokens(code, returnedState);
        setIsAuthenticated(true);
        await scheduleTokenRefresh();
        await loadUserInfo();
      } else if (result.type === 'error') {
        throw new Error(result.params?.error_description || 'Authentication failed');
      } else if (result.type === 'dismiss') {
        // User cancelled - not an error
        setError(null);
      }
    } catch (err) {
      setError(err.message);
      Alert.alert('Authentication Error', err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = async () => {
    setIsLoading(true);
    try {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
      await OAuthService.revokeTokens();
    } catch (err) {
      console.error('Logout error:', err);
    } finally {
      setIsAuthenticated(false);
      setUserInfo(null);
      setError(null);
      setIsLoading(false);
    }
  };

  const handleRefreshToken = async () => {
    setIsLoading(true);
    try {
      await OAuthService.refreshAccessToken();
      await scheduleTokenRefresh();
      Alert.alert('Success', 'Token refreshed successfully');
    } catch (err) {
      setError(err.message);
      Alert.alert('Refresh Error', err.message);
      setIsAuthenticated(false);
      setUserInfo(null);
    } finally {
      setIsLoading(false);
    }
  };

  const handleApiCall = async () => {
    try {
      const response = await ApiClient.fetch('https://api.example.com/protected-resource');
      const data = await response.json();
      Alert.alert('API Response', JSON.stringify(data, null, 2));
    } catch (err) {
      Alert.alert('API Error', err.message);
      if (err.message === 'Authentication expired' || err.message === 'Not authenticated') {
        setIsAuthenticated(false);
        setUserInfo(null);
      }
    }
  };

  if (isLoading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Loading...</Text>
      </View>
    );
  }

  return (
    <ScrollView contentContainerStyle={styles.container}>
      <Text style={styles.title}>OAuth 2.0 Mobile App</Text>
      <Text style={styles.subtitle}>Authorization Code Flow with PKCE</Text>

      {error && (
        <View style={styles.errorContainer}>
          <Text style={styles.errorText}>{error}</Text>
        </View>
      )}

      {!isAuthenticated ? (
        <View style={styles.section}>
          <Text style={styles.statusText}>Not Authenticated</Text>
          <TouchableOpacity style={styles.button} onPress={handleLogin}>
            <Text style={styles.buttonText}>Login with OAuth</Text>
          </TouchableOpacity>
          <Text style={styles.infoText}>
            Uses PKCE (Proof Key for Code Exchange) for secure public client authentication.
            No client_secret is embedded in the app.
          </Text>
        </View>
      ) : (
        <View style={styles.section}>
          <Text style={styles.statusText}>✓ Authenticated</Text>

          {userInfo && (
            <View style={styles.userInfoContainer}>
              <Text style={styles.userInfoTitle}>User Info</Text>
              <Text style={styles.userInfoText}>
                Name: {userInfo.name || 'N/A'}
              </Text>
              <Text style={styles.userInfoText}>
                Email: {userInfo.email || 'N/A'}
              </Text>
              <Text style={styles.userInfoText}>
                Sub: {userInfo.sub || 'N/A'}
              </Text>
            </View>
          )}

          <TouchableOpacity
            style={[styles.button, styles.secondaryButton]}
            onPress={handleRefreshToken}
          >
            <Text style={styles.buttonText}>Refresh Token</Text>
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.button, styles.secondaryButton]}
            onPress={handleApiCall}
          >
            <Text style={styles.buttonText}>Test API Call</Text>
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.button, styles.dangerButton]}
            onPress={handleLogout}
          >
            <Text style={styles.buttonText}>Logout</Text>
          </TouchableOpacity>
        </View>
      )}

      <View style={styles.configInfo}>
        <Text style={styles.configTitle}>Security Features</Text>
        <Text style={styles.configText}>• PKCE (S256) for public client security</Text>
        <Text style={styles.configText}>• No client_secret in mobile app</Text>
        <Text style={styles.configText}>• Tokens stored in SecureStore (Keychain/Keystore)</Text>
        <Text style={styles.configText}>• CSRF protection via state parameter</Text>
        <Text style={styles.configText}>• Automatic token refresh</Text>
        <Text style={styles.configText}>• Token revocation on logout</Text>
        <Text style={styles.configText}>• Redirect URI: {OAUTH_CONFIG.redirectUri}</Text>
      </View>
    </ScrollView>
  );
}

